var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양! 물러서세요!","JPN":"ミナさん！　下がってください！","ENG":"Mina! Fall back!","TWN":"米娜！走開！"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자칫하면 그림자들에게 포위당합니다!","JPN":"下手をすればシャドウに囲まれます！","ENG":"One wrong move and you’ll be surrounded by Shadows!","TWN":"萬一有個什麼差錯，你會被暗影包圍的！"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만…… 저기, 저기서 소대장과 싸우고 있는 건……","JPN":"けど……あれ、あそこで小隊長と戦っているのは……","ENG":"But... Th-the thing that the Commander is fighting...","TWN":"可是……在那裡和小隊長對打的……"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나잖아?","JPN":"私？","ENG":"...That’s me.","TWN":"不就是我嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"아니. 그렇지 않아.","JPN":"いや、そうじゃないよ。","ENG":"No, that’s not true.","TWN":"不，不是的。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"저건 부활의 지팡이로 만들어낸 육신에 세라펠의 실을 짜 넣어서 조종하는 인형일 뿐.","JPN":"あれは復活の杖が作り出した肉体にセラフェルの糸を編みこんで操られている人形に過ぎない。","ENG":"That’s merely a puppet created by stuffing a body made with the Staff of Resurrection with Serapel’s strings.","TWN":"那只是將塞拉費爾的線，放入以復活之杖製造出來的軀體中，再加以控制的木偶而已。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"네 피가 한 방울 섞여 있다는 건 인정하지만, 그건 반창고도 마찬가지지.","JPN":"君の血が1滴混じってはいるけど、それは絆創膏程度だよね。","ENG":"I admit that a drop of my blood is also mixed in, but the same could be said for a band-aid.","TWN":"雖然是有混到一滴你的血，但量就跟OK繃上的差不多。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"늑대의 긍지도 없는 저런 모조품을 우리라고 인정하지 마.","JPN":"狼の誇りもないあんな模造品を私たちだと思わないで。","ENG":"Don’t acknowledge such imitations that lack a Wolf’s pride as us.","TWN":"像那種完全沒有狼的自負的複製品，才不是我們！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"넌…… 또 여기야?","JPN":"あんた……またここなの？","ENG":"You’re... I’m here again?","TWN":"你……我怎麼又在這裡？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"그래. 결국 아무것도 모르는 채로 클리포트 게임의 열쇠를 돌려 버렸구나.","JPN":"そう。結局何も知らないままクリフォトゲームの扉を開けてしまったのね。","ENG":"Yeah, it looks like you’ve turned the key to the Qliphoth Game without knowing anything about it.","TWN":"沒錯，結果你還是在不知情的情況下，轉動了逆卡巴拉遊戲的鑰匙。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"하지만 넌 아직 준비가 되지 못했지.","JPN":"でも、君はまだ十分に準備ができていない。","ENG":"However, you’re not ready yet.","TWN":"可是你又還沒準備好，"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"불쌍한 나의 스승은…… 또 한 번 상처 받을 테고.","JPN":"かわいそうな師匠は……また傷つくだろうね。","ENG":"My poor master... She’ll get hurt again.","TWN":"我可憐的師父……又會經歷到二次傷害，"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"아무도 알아주지 않는 혼자만의 상처를.","JPN":"本人にしかわからないだろうけど。","ENG":"A scar that she will have to bear by herself.","TWN":"而且是只能獨自承受的傷害。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 뜻이야, 그건?","JPN":"どういうこと？","ENG":"What’s that supposed to mean?","TWN":"那是什麼意思？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"힐데 소대장이 상처를 받는다고? 고작 내 모습을 본딴 도플갱어와 싸우는 걸로?","JPN":"ヒルデ小隊長が傷つく？　私の姿を真似たドッペルゲンガーと戦って？","ENG":"Commander Hilde getting hurt? Just by fighting a Doppelganger with my appearance?","TWN":"希爾德小隊長會受傷？對手不過是模仿我的二重身而已欸？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아.","JPN":"そんなはずないよ。","ENG":"There’s no way.","TWN":"這怎麼可能！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"넌 잘 모르겠지만…… 우린 그렇게 친한 관계가 아니야.","JPN":"あんたはよくわからないけど……師匠とはそんなに親しい間柄じゃない。","ENG":"You may not know... But we aren’t that close with each other.","TWN":"你好像不太清楚……我們並沒有很熟。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"……아무것도 모르는 건 너야. 불쌍하게도.","JPN":"……何も知らないのは君の方だよ。かわいそうに。","ENG":"...You’re the one who knows nothing, you poor thing.","TWN":"……不清楚的是你，真是可憐。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};